import os
import json

def list_files(page_size: int = 20, order_by: str = "modifiedTime desc") -> str:
    """List files in Google Drive. Returns file names, IDs, and MIME types. Use page_size to control how many results to return (default 20). order_by can be 'modifiedTime desc', 'name', 'createdTime desc', etc."""
    try:
        import requests
        access_token = GOOGLE_DRIVE_ACCESS_TOKEN
        if not access_token:
            return "Error: GOOGLE_DRIVE_ACCESS_TOKEN environment variable is not set. Please configure it with a valid OAuth2 access token."

        headers = {"Authorization": f"Bearer {access_token}"}
        params = {
            "pageSize": page_size,
            "orderBy": order_by,
            "fields": "files(id,name,mimeType,size,modifiedTime,createdTime),nextPageToken"
        }
        response = requests.get("https://www.googleapis.com/drive/v3/files", headers=headers, params=params, timeout=30)

        if response.status_code == 401:
            return "Error: Access token is invalid or expired. Please refresh your Google Drive OAuth2 token."
        if response.status_code != 200:
            return f"Error: Google Drive API returned status {response.status_code}: {response.text}"

        data = response.json()
        files = data.get("files", [])
        if not files:
            return "No files found in Google Drive."

        result = f"Found {len(files)} file(s):\n\n"
        for f in files:
            size = f.get('size', 'N/A')
            modified = f.get('modifiedTime', 'N/A')
            result += f"- **{f['name']}**\n  ID: {f['id']}\n  Type: {f['mimeType']}\n  Size: {size} bytes\n  Modified: {modified}\n\n"

        if data.get("nextPageToken"):
            result += "(More files available — refine your search or increase page_size)"
        return result
    except Exception as e:
        return f"Error listing files: {str(e)}"


def search_files(query: str, page_size: int = 20) -> str:
    """Search for files in Google Drive by name or custom query. The query parameter can be a simple file name (will search by name contains) or a full Google Drive query string (e.g., "mimeType='application/pdf'")."""
    try:
        import requests
        access_token = GOOGLE_DRIVE_ACCESS_TOKEN
        if not access_token:
            return "Error: GOOGLE_DRIVE_ACCESS_TOKEN environment variable is not set. Please configure it with a valid OAuth2 access token."

        headers = {"Authorization": f"Bearer {access_token}"}

        # If the query doesn't look like a Drive API query, wrap it as a name search
        if "=" not in query and "contains" not in query and "in" not in query:
            drive_query = f"name contains '{query}' and trashed = false"
        else:
            drive_query = query

        params = {
            "q": drive_query,
            "pageSize": page_size,
            "fields": "files(id,name,mimeType,size,modifiedTime,createdTime),nextPageToken"
        }
        response = requests.get("https://www.googleapis.com/drive/v3/files", headers=headers, params=params, timeout=30)

        if response.status_code == 401:
            return "Error: Access token is invalid or expired. Please refresh your Google Drive OAuth2 token."
        if response.status_code != 200:
            return f"Error: Google Drive API returned status {response.status_code}: {response.text}"

        data = response.json()
        files = data.get("files", [])
        if not files:
            return f"No files found matching query: {query}"

        result = f"Found {len(files)} file(s) matching '{query}':\n\n"
        for f in files:
            size = f.get('size', 'N/A')
            modified = f.get('modifiedTime', 'N/A')
            result += f"- **{f['name']}**\n  ID: {f['id']}\n  Type: {f['mimeType']}\n  Size: {size} bytes\n  Modified: {modified}\n\n"
        return result
    except Exception as e:
        return f"Error searching files: {str(e)}"


def read_file(file_id: str) -> str:
    """Read/download the content of a file from Google Drive by its file ID. Works best with text-based files. For Google Docs/Sheets/Slides, it exports as plain text or CSV."""
    try:
        import requests
        access_token = GOOGLE_DRIVE_ACCESS_TOKEN
        if not access_token:
            return "Error: GOOGLE_DRIVE_ACCESS_TOKEN environment variable is not set. Please configure it with a valid OAuth2 access token."

        headers = {"Authorization": f"Bearer {access_token}"}

        # First get file metadata to determine type
        meta_response = requests.get(
            f"https://www.googleapis.com/drive/v3/files/{file_id}",
            headers=headers,
            params={"fields": "id,name,mimeType,size"},
            timeout=30
        )

        if meta_response.status_code == 401:
            return "Error: Access token is invalid or expired. Please refresh your Google Drive OAuth2 token."
        if meta_response.status_code == 404:
            return f"Error: File with ID '{file_id}' not found."
        if meta_response.status_code != 200:
            return f"Error getting file metadata: {meta_response.status_code}: {meta_response.text}"

        meta = meta_response.json()
        mime_type = meta.get("mimeType", "")
        file_name = meta.get("name", "Unknown")

        # Google Workspace files need to be exported
        export_mime_map = {
            "application/vnd.google-apps.document": "text/plain",
            "application/vnd.google-apps.spreadsheet": "text/csv",
            "application/vnd.google-apps.presentation": "text/plain",
            "application/vnd.google-apps.drawing": "image/png",
        }

        if mime_type in export_mime_map:
            export_mime = export_mime_map[mime_type]
            response = requests.get(
                f"https://www.googleapis.com/drive/v3/files/{file_id}/export",
                headers=headers,
                params={"mimeType": export_mime},
                timeout=60
            )
        else:
            response = requests.get(
                f"https://www.googleapis.com/drive/v3/files/{file_id}",
                headers=headers,
                params={"alt": "media"},
                timeout=60
            )

        if response.status_code != 200:
            return f"Error downloading file: {response.status_code}: {response.text}"

        # Try to decode as text
        try:
            content = response.text
            return f"**File: {file_name}** (Type: {mime_type})\n\n---\n{content}"
        except Exception:
            return f"File '{file_name}' was downloaded but appears to be binary content (Type: {mime_type}). Cannot display binary files as text."
    except Exception as e:
        return f"Error reading file: {str(e)}"


def upload_file(file_name: str, content: str, mime_type: str = "text/plain", folder_id: str = "") -> str:
    """Upload/create a new file to Google Drive with the given content. Provide the file_name, text content, and optionally a mime_type (default: text/plain) and folder_id to place it in a specific folder."""
    try:
        import requests
        access_token = GOOGLE_DRIVE_ACCESS_TOKEN
        if not access_token:
            return "Error: GOOGLE_DRIVE_ACCESS_TOKEN environment variable is not set. Please configure it with a valid OAuth2 access token."

        headers = {"Authorization": f"Bearer {access_token}"}

        # Build metadata
        metadata = {"name": file_name}
        if folder_id:
            metadata["parents"] = [folder_id]

        # Use multipart upload
        boundary = "----ToolBoundary"
        body = (
            f"--{boundary}\r\n"
            f"Content-Type: application/json; charset=UTF-8\r\n\r\n"
            f"{json.dumps(metadata)}\r\n"
            f"--{boundary}\r\n"
            f"Content-Type: {mime_type}\r\n\r\n"
            f"{content}\r\n"
            f"--{boundary}--"
        )

        upload_headers = {
            "Authorization": f"Bearer {access_token}",
            "Content-Type": f"multipart/related; boundary={boundary}"
        }

        response = requests.post(
            "https://www.googleapis.com/upload/drive/v3/files?uploadType=multipart",
            headers=upload_headers,
            data=body.encode("utf-8"),
            timeout=60
        )

        if response.status_code == 401:
            return "Error: Access token is invalid or expired. Please refresh your Google Drive OAuth2 token."
        if response.status_code not in [200, 201]:
            return f"Error uploading file: {response.status_code}: {response.text}"

        result = response.json()
        return f"File uploaded successfully!\n- **Name:** {result.get('name')}\n- **ID:** {result.get('id')}\n- **Type:** {result.get('mimeType')}"
    except Exception as e:
        return f"Error uploading file: {str(e)}"


def update_file(file_id: str, content: str, mime_type: str = "text/plain", new_name: str = "") -> str:
    """Update an existing file's content in Google Drive by its file ID. Optionally rename the file by providing new_name."""
    try:
        import requests
        access_token = GOOGLE_DRIVE_ACCESS_TOKEN
        if not access_token:
            return "Error: GOOGLE_DRIVE_ACCESS_TOKEN environment variable is not set. Please configure it with a valid OAuth2 access token."

        headers = {"Authorization": f"Bearer {access_token}"}

        # Build metadata
        metadata = {}
        if new_name:
            metadata["name"] = new_name

        boundary = "----ToolBoundary"
        body = (
            f"--{boundary}\r\n"
            f"Content-Type: application/json; charset=UTF-8\r\n\r\n"
            f"{json.dumps(metadata)}\r\n"
            f"--{boundary}\r\n"
            f"Content-Type: {mime_type}\r\n\r\n"
            f"{content}\r\n"
            f"--{boundary}--"
        )

        upload_headers = {
            "Authorization": f"Bearer {access_token}",
            "Content-Type": f"multipart/related; boundary={boundary}"
        }

        response = requests.patch(
            f"https://www.googleapis.com/upload/drive/v3/files/{file_id}?uploadType=multipart",
            headers=upload_headers,
            data=body.encode("utf-8"),
            timeout=60
        )

        if response.status_code == 401:
            return "Error: Access token is invalid or expired. Please refresh your Google Drive OAuth2 token."
        if response.status_code == 404:
            return f"Error: File with ID '{file_id}' not found."
        if response.status_code != 200:
            return f"Error updating file: {response.status_code}: {response.text}"

        result = response.json()
        return f"File updated successfully!\n- **Name:** {result.get('name')}\n- **ID:** {result.get('id')}\n- **Type:** {result.get('mimeType')}"
    except Exception as e:
        return f"Error updating file: {str(e)}"


def delete_file(file_id: str) -> str:
    """Delete a file from Google Drive by its file ID. This action is permanent — use with caution."""
    try:
        import requests
        access_token = GOOGLE_DRIVE_ACCESS_TOKEN
        if not access_token:
            return "Error: GOOGLE_DRIVE_ACCESS_TOKEN environment variable is not set. Please configure it with a valid OAuth2 access token."

        headers = {"Authorization": f"Bearer {access_token}"}

        # First get file info to confirm
        meta_response = requests.get(
            f"https://www.googleapis.com/drive/v3/files/{file_id}",
            headers=headers,
            params={"fields": "id,name,mimeType"},
            timeout=30
        )

        if meta_response.status_code == 404:
            return f"Error: File with ID '{file_id}' not found."

        file_name = "Unknown"
        if meta_response.status_code == 200:
            file_name = meta_response.json().get("name", "Unknown")

        response = requests.delete(
            f"https://www.googleapis.com/drive/v3/files/{file_id}",
            headers=headers,
            timeout=30
        )

        if response.status_code == 401:
            return "Error: Access token is invalid or expired. Please refresh your Google Drive OAuth2 token."
        if response.status_code == 404:
            return f"Error: File with ID '{file_id}' not found."
        if response.status_code not in [200, 204]:
            return f"Error deleting file: {response.status_code}: {response.text}"

        return f"File '{file_name}' (ID: {file_id}) has been permanently deleted."
    except Exception as e:
        return f"Error deleting file: {str(e)}"


def get_file_info(file_id: str) -> str:
    """Get detailed metadata/information about a specific file in Google Drive by its file ID."""
    try:
        import requests
        access_token = GOOGLE_DRIVE_ACCESS_TOKEN
        if not access_token:
            return "Error: GOOGLE_DRIVE_ACCESS_TOKEN environment variable is not set. Please configure it with a valid OAuth2 access token."

        headers = {"Authorization": f"Bearer {access_token}"}
        params = {"fields": "id,name,mimeType,size,createdTime,modifiedTime,owners,shared,webViewLink,parents,description"}

        response = requests.get(
            f"https://www.googleapis.com/drive/v3/files/{file_id}",
            headers=headers,
            params=params,
            timeout=30
        )

        if response.status_code == 401:
            return "Error: Access token is invalid or expired. Please refresh your Google Drive OAuth2 token."
        if response.status_code == 404:
            return f"Error: File with ID '{file_id}' not found."
        if response.status_code != 200:
            return f"Error getting file info: {response.status_code}: {response.text}"

        f = response.json()
        owners = ", ".join([o.get("displayName", "Unknown") for o in f.get("owners", [])]) or "N/A"

        result = (
            f"**File Information:**\n\n"
            f"- **Name:** {f.get('name', 'N/A')}\n"
            f"- **ID:** {f.get('id', 'N/A')}\n"
            f"- **Type:** {f.get('mimeType', 'N/A')}\n"
            f"- **Size:** {f.get('size', 'N/A')} bytes\n"
            f"- **Created:** {f.get('createdTime', 'N/A')}\n"
            f"- **Modified:** {f.get('modifiedTime', 'N/A')}\n"
            f"- **Owner(s):** {owners}\n"
            f"- **Shared:** {f.get('shared', 'N/A')}\n"
            f"- **Web Link:** {f.get('webViewLink', 'N/A')}\n"
            f"- **Description:** {f.get('description', 'None')}\n"
        )
        return result
    except Exception as e:
        return f"Error getting file info: {str(e)}"
